```javascript
const { exec } = require('child_process');

function pingIP(ip) {
  return new Promise((resolve, reject) => {
    exec(`ping -c 1 -W 1 ${ip}`, { timeout: 2000 }, (error) => {
      if (error) {
        reject(error);
      } else {
        resolve(ip);
      }
    });
  });
}

async function sortIPs(ipList) {
  const sortedIps = [];

  for (let ip of ipList) {
    try {
      const accessibleIp = await pingIP(ip);
      sortedIps.push(accessibleIp);
    } catch (error) {
      // IP is not accessible or timed out, don't add to the list
    }
  }

  return sortedIps;
}

if (require.main === module) {
  const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
  });

  readline.question('Enter IP addresses (comma-separated): ', (ipInput) => {
    const ips = ipInput.split(',').map(ip => ip.trim());

    sortIPs(ips).then((sortedIps) => {
      // Wait for 5 seconds (adjust as per your requirements)
      setTimeout(() => {
        console.log('Sorted IP addresses:');
        for (const ip of sortedIps) {
          console.log(ip);
        }
        readline.close();
      }, 5000);
    });
  });
}
```

