Here's an example implementation using the `http` module. Please note that this script will check for HTTP (not HTTPS) connectivity, assuming the target servers are listening on the standard HTTP port (80):

```javascript
const http = require('http');

function checkHTTPConnectivity(ip, timeout = 3000) {
  return new Promise((resolve, reject) => {
    const request = http.get({
      host: ip,
      path: '/',
      timeout: timeout,
    }, (response) => {
      // We consider the IP address as reachable if we receive any HTTP response
      resolve(ip);
    });

    request.on('timeout', () => {
      request.abort();  // Aborts the request if the timeout is reached
      reject(new Error(`Timeout reached for ${ip}`));
    });

    request.on('error', (error) => {
      reject(error); // Handles general errors
    });
  });
}

async function filterIPs(ipList, timeout) {
  const reachableIps = [];

  for (let ip of ipList) {
    try {
      const reachableIp = await checkHTTPConnectivity(ip, timeout);
      reachableIps.push(reachableIp);
    } catch (error) {
      // IP is not reachable or timed out, don't add to the list
      console.error(`Error for ${ip}: ${error.message}`);
    }
  }

  return reachableIps;
}

if (require.main === module) {
  const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
  });

  readline.question('Enter IP addresses (comma-separated): ', (ipInput) => {
    const ips = ipInput.split(',').map(ip => ip.trim());

    // Modify the timeout as needed (2-3 seconds)
    const timeout = 3000;

    filterIPs(ips, timeout).then((reachableIps) => {
      console.log('IP addresses with HTTP response:');
      reachableIps.forEach(ip => console.log(ip));
      readline.close();
    });
  });
}
```

