  function testBridgeIP(ip, timeout) {
    return new Promise((resolve, reject) => {
      const img = new Image();

      const timer = setTimeout(() => {
        img.onerror = img.onload = null;  // Prevent memory leaks
        reject(new Error('Timeout'));
      }, timeout);

      img.onerror = () => {
        clearTimeout(timer);
        reject(new Error('Error loading image'));
      };

      img.onload = () => {
        clearTimeout(timer);
        resolve(ip);
      };

      // Try loading a small, commonly existing image or endpoint
      img.src = `http://${ip}/favicon.ico?_=${Math.random()}`;  // Cache Busting
