  document.getElementById('checkButton').addEventListener('click', () => {
    const ips = document.getElementById('ipList').value.split(',').map(ip => ip.trim());
    const resultDiv = document.getElementById('result');
    resultDiv.textContent = 'Checking IPs...';

    const timeout = 3000; // Set a timeout
    const checks = ips.map(ip => testBridgeIP(ip, timeout).catch(() => `${ip} - Failed`));

    Promise.all(checks).then(results => {
      resultDiv.textContent = results.join('\n');
    });
